const input = $input.first().json;
const command = (input.command || '').toLowerCase().trim();

let action = input.action || 'unknown';
if (action === 'unknown') {
  if (command.includes('check') || command.includes('availability') || command.includes('free')) action = 'check';
  else if (command.includes('reschedule') || command.includes('move') || command.includes('change time')) action = 'reschedule';
  else if (command.includes('schedule') || command.includes('book') || command.includes('create')) action = 'schedule';
}

if (!command) {
  throw new Error('No command text provided to calendar agent');
}

return [{
  json: {
    command: input.command,
    action: action,
    parameters: input.parameters || {},
    execution_id: input.execution_id || $execution.id,
    timestamp: new Date().toISOString()
  }
}];

// ⚠️ TEMPLATE PLACEHOLDER — This node marks the approval point but does NOT block execution.
// For production: Replace this Code node with an n8n Wait node (wait for webhook resume)
// or an n8n Form node for interactive approval.
// See: https://docs.n8n.io/integrations/builtin/core-nodes/n8n-nodes-base.wait/

const input = $input.first().json;
return [{
  json: {
    ...input,
    approval_status: 'pending',
    approval_required: true,
    approval_reason: 'write_operation_create_event',
    approval_message: `Approval required to create calendar event. Attendee: ${input.parameters?.attendee || 'N/A'}, Time: ${input.parameters?.time || 'N/A'}, Topic: ${input.parameters?.topic || 'N/A'}`,
    queued_at: new Date().toISOString()
  }
}];

// ⚠️ TEMPLATE PLACEHOLDER — This node marks the approval point but does NOT block execution.
// For production: Replace this Code node with an n8n Wait node (wait for webhook resume)
// or an n8n Form node for interactive approval.
// See: https://docs.n8n.io/integrations/builtin/core-nodes/n8n-nodes-base.wait/

const input = $input.first().json;
return [{
  json: {
    ...input,
    approval_status: 'pending',
    approval_required: true,
    approval_reason: 'write_operation_update_event',
    approval_message: `Approval required to reschedule event. Command: "${input.command}"`,
    queued_at: new Date().toISOString()
  }
}];

const input = $input.first().json;
return [{
  json: {
    agent: '1001-agent-calendar',
    action: input.action,
    confidence: 0.2,
    result: {
      error: `Unsupported calendar action: ${input.action}`,
      supported_actions: ['check', 'schedule', 'reschedule']
    },
    requires_approval: false,
    execution_time_ms: 0
  }
}];

const startTime = new Date($('Parse Calendar Command').first().json.timestamp).getTime();
const input = $input.first().json;
const parsed = $('Parse Calendar Command').first().json;

let result = {};
let confidence = 0.5;

try {
  if (input.items) {
    // Calendar API response (check action)
    const events = (input.items || []).map(e => ({
      summary: e.summary,
      start: e.start?.dateTime || e.start?.date,
      end: e.end?.dateTime || e.end?.date,
      attendees: (e.attendees || []).map(a => a.email)
    }));
    result = { events: events, count: events.length };
    confidence = 0.92;
  } else if (input.approval_required) {
    result = { message: input.approval_message, status: 'pending_approval' };
    confidence = 0.88;
  } else if (input.htmlLink) {
    // Successful create/update
    result = { event_link: input.htmlLink, status: 'created', event_id: input.id };
    confidence = 0.95;
  } else {
    result = input.result || input;
    confidence = input.confidence || 0.5;
  }
} catch (e) {
  result = { raw: input, parse_error: e.message };
  confidence = 0.3;
}

const isWriteOp = ['schedule', 'reschedule'].includes(parsed.action);
const executionTime = Date.now() - startTime;

return [{
  json: {
    agent: '1001-agent-calendar',
    action: parsed.action,
    confidence: confidence,
    result: result,
    requires_approval: isWriteOp,
    approval_reason: isWriteOp ? 'write_operation' : null,
    execution_time_ms: executionTime,
    execution_id: parsed.execution_id
  }
}];
